class MyHashMap:
    def __init__(self, capacity=100):
        self.capacity = capacity
        self.size = 0
        self.buckets = [[] for _ in range(self.capacity)]

    def _hash(self, key):
        return hash(key) % self.capacity

    def put(self, key, value):
        hash_index = self._hash(key)
        bucket = self.buckets[hash_index]

        for i, (k, v) in enumerate(bucket):
            if k == key:
                bucket[i] = (key, value)
                return

        bucket.append((key, value))
        self.size += 1

    def get(self, key):
        hash_index = self._hash(key)
        bucket = self.buckets[hash_index]

        for k, v in bucket:
            if k == key:
                return v
        return None

    def remove(self, key):
        hash_index = self._hash(key)
        bucket = self.buckets[hash_index]

        for i, (k, v) in enumerate(bucket):
            if k == key:
                del bucket[i]
                self.size -= 1
                return

    def __len__(self):
        return self.size

    def __contains__(self, key):
        return self.get(key) is not None

    def __getitem__(self, key):
        value = self.get(key)
        if value is None:
            raise KeyError(f"Key '{key}' not found")
        return value

    def __setitem__(self, key, value):
        self.put(key, value)

    def __delitem__(self, key):
        hash_index = self._hash(key)
        bucket = self.buckets[hash_index]

        for i, (k, v) in enumerate(bucket):
            if k == key:
                del bucket[i]
                self.size -= 1
                return
        raise KeyError(f"Key '{key}' not found")

    def __str__(self):
        items = []
        for bucket in self.buckets:
            for k, v in bucket:
                items.append(f"{repr(k)}: {repr(v)}")
        return "{" + ", ".join(items) + "}"

    def __repr__(self):
        return self.__str__()
